import * as React from "react";
import type { NormalizedTask } from "../../../../src/features/tasks/task-model";

interface KanbanCardProps {
	task: NormalizedTask;
	onClick?: () => void;
}

export const KanbanCard: React.FC<KanbanCardProps> = ({ task, onClick }) => {
	const metadata = task.metadata || {};
	const execution = task.execution || {};

	// Mock data for timestamps and agent ownership if not present
	const agentOwnership = execution.suggestedRole || "Unassigned";
	const blockers = execution.dependsOn && execution.dependsOn.length > 0 ? execution.dependsOn.join(", ") : null;

	return (
		<div 
			className="kanban-card" 
			onClick={onClick}
			style={{
				backgroundColor: "var(--vscode-editor-background)",
				border: "1px solid var(--vscode-widget-border)",
				padding: "8px",
				marginBottom: "8px",
				borderRadius: "4px",
				cursor: onClick ? "pointer" : "default",
				display: "flex",
				flexDirection: "column",
				gap: "4px"
			}}
		>
			<div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
				<span style={{ fontWeight: "bold", fontSize: "13px", color: "var(--vscode-editor-foreground)" }}>
					{task.title}
				</span>
				{metadata.priority && (
					<span style={{ fontSize: "10px", padding: "2px 4px", backgroundColor: "var(--vscode-badge-background)", color: "var(--vscode-badge-foreground)", borderRadius: "2px" }}>
						{metadata.priority}
					</span>
				)}
			</div>

			<div style={{ fontSize: "11px", color: "var(--vscode-descriptionForeground)" }}>
				<div>Source: {task.source.system}</div>
				{agentOwnership && <div>Agent: {agentOwnership}</div>}
				{blockers && <div style={{ color: "var(--vscode-errorForeground)" }}>Blocked by: {blockers}</div>}
				{execution.errorMessage && <div style={{ color: "var(--vscode-errorForeground)" }}>Error: {execution.errorMessage}</div>}
				{execution.intent && <div style={{ marginTop: "4px", fontStyle: "italic", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>Activity: {execution.intent}</div>}
			</div>
		</div>
	);
};

import * as React from "react";
import type { NormalizedTask, ExecutionState } from "../../../../src/features/tasks/task-model";
import { KanbanCard } from "./kanban-card";

interface KanbanColumnProps {
	title: string;
	state: ExecutionState;
	tasks: NormalizedTask[];
	onTaskClick?: (task: NormalizedTask) => void;
}

export const KanbanColumn: React.FC<KanbanColumnProps> = ({ title, state, tasks, onTaskClick }) => {
	return (
		<div
			className="kanban-column"
			style={{
				display: "flex",
				flexDirection: "column",
				flex: "1 1 0",
				minWidth: "250px",
				backgroundColor: "var(--vscode-sideBar-background)",
				border: "1px solid var(--vscode-widget-border)",
				borderRadius: "4px",
				overflow: "hidden"
			}}
		>
			<div 
				style={{ 
					padding: "8px", 
					fontWeight: "bold", 
					borderBottom: "1px solid var(--vscode-widget-border)",
					backgroundColor: "var(--vscode-editorGroupHeader-tabsBackground)",
					color: "var(--vscode-editorGroupHeader-tabsForeground)",
					display: "flex",
					justifyContent: "space-between"
				}}
			>
				<span>{title}</span>
				<span style={{ 
					backgroundColor: "var(--vscode-badge-background)", 
					color: "var(--vscode-badge-foreground)",
					padding: "0 6px",
					borderRadius: "10px",
					fontSize: "11px"
				}}>
					{tasks.length}
				</span>
			</div>
			<div 
				style={{ 
					padding: "8px", 
					overflowY: "auto",
					flex: 1
				}}
			>
				{tasks.map(task => (
					<KanbanCard 
						key={task.id} 
						task={task} 
						onClick={() => onTaskClick?.(task)} 
					/>
				))}
				{tasks.length === 0 && (
					<div style={{ textAlign: "center", padding: "16px", color: "var(--vscode-descriptionForeground)", fontSize: "12px", fontStyle: "italic" }}>
						No tasks
					</div>
				)}
			</div>
		</div>
	);
};

import * as React from "react";
import type { NormalizedTask, ExecutionState } from "../../../../src/features/tasks/task-model";
import { KanbanColumn } from "./kanban-column";

interface KanbanBoardProps {
	tasks: NormalizedTask[];
	onTaskClick?: (task: NormalizedTask) => void;
}

export const KanbanBoard: React.FC<KanbanBoardProps> = ({ tasks, onTaskClick }) => {
	// Group tasks by execution state
	// "Implement columns for queued, ready, running, blocked, completed, and failed work"

	const getTasksByState = (state: ExecutionState) => {
		return tasks.filter(t => t.execution?.state === state);
	};

	const columns: { title: string; state: ExecutionState }[] = [
		{ title: "Queued", state: "queued" },
		{ title: "Ready", state: "ready" },
		{ title: "Running", state: "running" },
		{ title: "Blocked", state: "blocked" },
		{ title: "Completed", state: "completed" },
		{ title: "Failed", state: "failed" }
	];

	return (
		<div 
			className="kanban-board"
			style={{
				display: "flex",
				gap: "16px",
				padding: "16px",
				height: "100%",
				width: "100%",
				overflowX: "auto",
				boxSizing: "border-box",
				color: "var(--vscode-editor-foreground)",
				backgroundColor: "var(--vscode-editor-background)"
			}}
